class Solution:
    def longestWPI(self, hours):
        n = len(hours)
        score = [1 if h > 8 else -1 for h in hours]
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + score[i]
        best = 0
        for i in range(n + 1):
            for j in range(i + 1, n + 1):
                if prefix[j] - prefix[i] > 0:
                    best = max(best, j - i)
        return best

solutions.python:
class Solution:
    def longestWPI(self, hours):
        running = 0
        first = {}
        best = 0
        for i, h in enumerate(hours):
            running += 1 if h > 8 else -1
            if running > 0:
                best = i + 1
            else:
                if running not in first:
                    first[running] = i
                if (running - 1) in first:
                    best = max(best, i - first[running - 1])
        return best

