var longestWPI = function(hours) {
    let running = 0, best = 0;
    const first = new Map();
    for (let i = 0; i < hours.length; i++) {
        running += hours[i] > 8 ? 1 : -1;
        if (running > 0) {
            best = i + 1;
        } else {
            if (!first.has(running)) first.set(running, i);
            if (first.has(running - 1)) best = Math.max(best, i - first.get(running - 1));
        }
    }
    return best;
};
